mapper.select:
SELECT m.milestone_id, m.project_id, m.user_code, m.milestone_title, m.milestone_describe, m.finish_date, m.milestone_status AS milestone_status, m.created_at, m.updated_at, NVL(stats.total_count, 0) AS total_task_count, NVL(stats.closed_count, 0) AS closed_task_count, NVL(stats.avg_progress, 0) AS progress_percentage,
CASE WHEN NVL(stats.avg_progress, 0) < 100 AND TRUNC(SYSDATE) > TRUNC(m.finish_date) THEN TRUNC(SYSDATE) - TRUNC(m.finish_date) ELSE 0 END AS delay_days,
t.task_id, t.task_title, t.task_progress, t.finish_date AS task_finish_date, u.user_name AS task_manager_name, tt.type_name AS type_name, cc.default_describe AS default_describe FROM milestone m
/* [튜닝 1] 해당 프로젝트의 일감만 그룹바이 하도록 서브쿼리 내부 필터링 추가 */ LEFT JOIN ( SELECT milestone_id, COUNT(*) AS total_count, COUNT(CASE WHEN task_progress = 100 THEN 1 END) AS closed_count, ROUND(AVG(NVL(task_progress, 0))) AS avg_progress FROM task WHERE project_id = #{projectId} GROUP BY milestone_id ) stats ON m.milestone_id = stats.milestone_id
/* [튜닝 2] 해당 프로젝트의 일감 범위 내에서만 정렬 및 ROW_NUMBER()를 매기도록 수정 */ LEFT JOIN ( SELECT tk.task_id, tk.milestone_id, tk.task_title, tk.task_progress, tk.finish_date, tk.task_manager, tk.type_id, tk.task_status, tk.created_at, ROW_NUMBER() OVER (PARTITION BY milestone_id ORDER BY created_at DESC) AS rn FROM task tk WHERE project_id = #{projectId} ) t ON m.milestone_id = t.milestone_id AND t.rn <= 5
/* [튜닝 3] 일감이 가진 담당자 회원코드와 일치하는 회원 정보 */ LEFT JOIN users u ON t.task_manager = u.user_code
/* [튜닝 4] 일감이 가진 일감유형 아이디와 일치하는 일감유형 정보 */ LEFT JOIN task_types tt ON t.type_id = tt.type_id
/* [튜닝 5] 일감이 가진 일감상태가 공통코드 테이블의 아이디와 일치하는 공통코드 정보 */ LEFT JOIN common_code cc ON t.task_status = cc.common_id WHERE m.project_id = #{projectId} ORDER BY m.created_at DESC, t.created_at DESC

SELECT m.milestone_id, m.project_id, m.user_code, m.milestone_title, m.milestone_describe, m.finish_date, m.milestone_status AS milestone_status, m.created_at, m.updated_at,
NVL(stats.total_count, 0) AS total_task_count, NVL(stats.closed_count, 0) AS closed_task_count, NVL(stats.avg_progress, 0) AS progress_percentage, CASE WHEN NVL(stats.avg_progress, 0) < 100 AND TRUNC(SYSDATE) > TRUNC(m.finish_date) THEN TRUNC(SYSDATE) - TRUNC(m.finish_date) ELSE 0 END AS delay_days,
NVL(stats.total_estimated, 0) AS total_estimated_hours, NVL(stats.total_spent, 0) AS total_spent_hours FROM milestone m LEFT JOIN ( SELECT milestone_id, COUNT(*) AS total_count, SUM(CASE WHEN task_status = 'e3' THEN 1 ELSE 0 END) AS closed_count, ROUND(AVG(NVL(task_progress, 0))) AS avg_progress, SUM(NVL(estimated_time, 0)) AS total_estimated, SUM(NVL(spent_hours_sum, 0)) AS total_spent FROM task WHERE milestone_id = #{milestoneId} AND project_id = #{projectId} GROUP BY milestone_id ) stats ON m.milestone_id = stats.milestone_id WHERE m.milestone_id = #{milestoneId} AND m.project_id = #{projectId}
